import React, { useState } from 'react';

const App = () => {
  const [credits, setCredits] = useState(20);
  const [profile, setProfile] = useState({ name: '' });
  return (
    <div className="min-h-screen bg-[#090a0f] text-white p-4 flex items-center justify-center">
      <div className="bg-white p-4 w-96">
        <h2>Credits: {credits}</h2>
        <button className="bg-[#411C56] hover:bg-[#C06C88] text-white font-bold py-2 px-4 rounded" onClick={() => setCredits(credits + 10)}>Add Credits</button>
        <button className="bg-[#C06C88] hover:bg-[#B7D7CD] text-white font-bold py-2 px-4 rounded" onClick={() => setCredits(credits - 10)}>Remove Credits</button>
        <form className="mt-4">
          <input type="text" placeholder="Name" value={profile.name} onChange={(e) => setProfile({ ...profile, name: e.target.value })} className="p-2 mb-2 w-full"/>
          <button className="bg-[#411C56] hover:bg-[#C06C88] text-white font-bold py-2 px-4 rounded" type="submit">Update Profile</button>
        </form>
      </div>
    </div>
  );
};

export default App;
